35	func commonBits(ip1, ip2 []byte) uint8 {
36		size := len(ip1)
37		if size == net.IPv4len {
38			a := binary.BigEndian.Uint32(ip1)
39			b := binary.BigEndian.Uint32(ip2)
40			x := a ^ b
41			return uint8(bits.LeadingZeros32(x))
