46			if x != 0 {
47				return uint8(bits.LeadingZeros64(x))
48			}
49			a = binary.BigEndian.Uint64(ip1[8:])
50			b = binary.BigEndian.Uint64(ip2[8:])
51			x = a ^ b
52			return 64 + uint8(bits.LeadingZeros64(x))
